import React, { useEffect, useState } from 'react';
import './empresasPanel.css';

const EmpresasPanel = () => {
  const [empresas, setEmpresas] = useState([]);
  const [imagenPreview, setImagenPreview] = useState(null);

  // Consumir datos del backend
  useEffect(() => {
    fetch('http://localhost:3001/api/empresas') // Asegúrate de poner tu ruta real aquí
      .then((res) => res.json())
      .then((data) => setEmpresas(data))
      .catch((error) => console.error('Error al obtener empresas:', error));
  }, []);

  // Manejar carga de imagen
  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      setImagenPreview(URL.createObjectURL(file));
      // Aquí podrías hacer un POST al backend si lo deseas
    }
  };

  return (
    <div className="empresas-panel-container">
      {/* Sección izquierda: subir imagen */}
      <div className="imagen-uploader">
        <h3>Subir Logo</h3>
        <input type="file" accept="image/*" onChange={handleImageUpload} />
        {imagenPreview && (
          <div className="imagen-preview">
            <img src={imagenPreview} alt="Preview" />
          </div>
        )}
      </div>

      {/* Sección derecha: lista de empresas */}
      <div className="empresas-panel">
        <h2 className="empresas-titulo">Empresas</h2>
        <div className="empresas-grid">
          {empresas.map((empresa, index) => (
            <div key={index} className="empresa-card">
              <img src={empresa.imagen} alt={empresa.nombre} className="empresa-imagen" />
              <h3 className="empresa-nombre">{empresa.nombre}</h3>
              <p className="empresa-descripcion">{empresa.descripcion}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default EmpresasPanel;
